      const { data: student } = await supabase.from("students").select("id, nombre").eq("numero", studentNum).eq("seccion", seccion).eq("a\xF1o", a\u00F1o).single();
      if (!student) throw new Error("Estudiante no encontrado");
      const { data: pagos } = await supabase.from("pagos").select("*").eq("student_id", student.id).eq("actividad_id", actividadId).eq("estado", "APROBADO").order("created_at", { ascending: true });
      let targetPago;
      if (abonoIndex === "pago_unico") {
        targetPago = pagos.find((p) => p.tipo === "pago_total");
      } else {
        const idx = parseInt(abonoIndex);
        targetPago = pagos[idx];
      }
      if (!targetPago) throw new Error("Pago no encontrado para revertir.");
      await supabase.from("pagos").delete().eq("id", targetPago.id);
      await supabase.from("historial").insert({
        actividad_id: actividadId,
        accion: "REVERTIDO",
        student_id: student.id,
        seccion,
        monto: targetPago.monto,
        aprobador: adminEmail,
        ref_sinpe: targetPago.referencia_sinpe,
        detalle: justificacion,
        a\u00F1o
      });
      await sendTelegram(`\u21A9\uFE0F <b>Pago revertido</b>
\u{1F464} <b>Estudiante:</b> ${student.nombre}
\u{1F4B0} <b>Monto:</b> \u20A1${targetPago.monto.toLocaleString("es-CR")}
\u{1F46E} <b>Admin:</b> ${adminEmail}
\u{1F4DD} <b>Raz\xF3n:</b> ${justificacion}`, env);
