  async function validateAnalysis(analysis, supabase, tipo = "abono", seccion = "1-1", a\u00F1o = 2027) {
    const phone = String(analysis.telefonoDestino || "").replace(/[-\s]/g, "");
    let validPhones = ["70228161", "83823869"];
    let alternatePhone = "83823869";
    try {
      const { data: secData, error: secError } = await supabase.from("seccion_docentes").select("sinpe_principal, sinpe_secundario").eq("seccion", seccion).eq("a\xF1o", parseInt(a\u00F1o)).maybeSingle();
      if (!secError && secData) {
        const p = String(secData.sinpe_principal || "").replace(/[-\s]/g, "");
        const s = String(secData.sinpe_secundario || "").replace(/[-\s]/g, "");
        if (p) {
          validPhones = [p];
          alternatePhone = "";
          if (s) {
            validPhones.push(s);
            alternatePhone = s;
          }
        }
      }
    } catch (e) {
      console.error("Error resolving dynamic SINPE:", e);
    }
    const isValidPhone = validPhones.includes(phone);
    const isAlternate = phone && phone === alternatePhone;
    let isDuplicate = false;
    if (analysis.referenciaSINPE) {
      const { data } = await supabase.from("pagos").select("id").eq("referencia_sinpe", analysis.referenciaSINPE).neq("estado", "RECHAZADO");
      if (data && data.length > 0) {
        isDuplicate = true;
      }
    }
    const flags = analysis.flags || {};
    let decision = analysis.recomendacion || "REVISAR";
    if (flags.posibleFalsificacion || flags.posibleIA || flags.textoEditado) {
      decision = "RECHAZAR";
    }
    if (isDuplicate) {
      decision = "RECHAZAR";
      analysis.razonScore = "N\xFAmero de referencia SINPE duplicado.";
    }
    if (tipo !== "devolucion" && phone && !isValidPhone) {
      decision = "REVISAR";
      analysis.razonScore = `El n\xFAmero de tel\xE9fono destino (${phone}) no coincide con el oficial de la secci\xF3n ${seccion} (${validPhones.join(", ")}).`;
    }
    if (analysis.monto < 1e3 || analysis.monto > 2e5) {
      decision = "REVISAR";
      analysis.razonScore = "El monto est\xE1 fuera del rango l\xF3gico permitido (\u20A11,000 - \u20A1200,000).";
    }
    return {
      ...analysis,
      isValidPhone,
      isAlternate,
      isDuplicate,
      decision
    };
  }
